const MARKUP = 1.10;
const amadeusOffers = $("Amadeus Flight Search").first()?.json?.data?.slice(0,3) || [];
const kiwiOffers    = $("Kiwi.com Flight Search").first()?.json?.data?.slice(0,2) || [];
const charter       = $("Check Charter Flights (Google Sheet)").first()?.json || null;

let comparison = "*\u2708\ufe0f Top Flight Options \u2014 Jude Travel Agency*\n\n";
let idx = 1;

if (charter && charter.route) {
  const finalPrice = (parseFloat(charter.price || 0) * MARKUP).toFixed(2);
  comparison += `*Option ${idx++}*\n`;
  comparison += `Route: ${charter.route}\nPrice: ${finalPrice} ${charter.currency || 'SAR'}\nDeparture: ${charter.departure}\n\n`;
}

amadeusOffers.forEach(o => {
  const seg = o.itineraries?.[0]?.segments?.[0] || {};
  const finalPrice = (parseFloat(o.price?.total || 0) * MARKUP).toFixed(2);
  comparison += `*Option ${idx++}*\n`;
  comparison += `${seg.departure?.iataCode} \u2192 ${seg.arrival?.iataCode}\n`;
  comparison += `Departure: ${seg.departure?.at}\nPrice: ${finalPrice} ${o.price?.currency || 'USD'}\n\n`;
});

kiwiOffers.slice(0, Math.max(0, 5 - idx)).forEach(o => {
  const finalPrice = (parseFloat(o.price || 0) * MARKUP).toFixed(2);
  comparison += `*Option ${idx++}*\n`;
  comparison += `${o.cityFrom} \u2192 ${o.cityTo}\n`;
  comparison += `Departure: ${o.local_departure}\nPrice: ${finalPrice} EUR\n\n`;
});

comparison += 'Please reply with the option number to book. / \u064a\u0631\u062c\u0649 \u0627\u0644\u0631\u062f \u0628\u0631\u0642\u0645 \u0627\u0644\u062e\u064a\u0627\u0631 \u0644\u0644\u062d\u062c\u0632.';
return [{ json: {
  comparison,
  sender_id:     $("Extract Flight Request").first().json.sender_id,
  customer_name: $("Extract Flight Request").first().json.customer_name
} }];

